static const unsigned char *unifont_lookup(unsigned short cp) {
  int lo = 0, hi = UNIFONT_COUNT - 1;
  while (lo <= hi) {
    int mid = (lo + hi) / 2;
    if (UNIFONT[mid].cp == cp) return UNIFONT[mid].data;
    if (UNIFONT[mid].cp < cp) lo = mid + 1; else hi = mid - 1;
  }
  return 0;
}

static const unsigned char *unifont_wide_lookup(unsigned short cp) {
  int lo = 0, hi = UNIFONT_WIDE_COUNT - 1;
  while (lo <= hi) {
    int mid = (lo + hi) / 2;
    if (UNIFONT_WIDE[mid].cp == cp) return UNIFONT_WIDE[mid].data;
    if (UNIFONT_WIDE[mid].cp < cp) lo = mid + 1; else hi = mid - 1;
  }
  return 0;
}

